const apiSecret = 'n8n_omniflow_bb381df03a4fa5e2706c0e11fd468468';
const baseUrl = 'https://osw.conectaai.cl/api/v1';
const phoneNumberId = $input.item.json.phone_number_id;

// Fallback — se usa si el tenant no tiene config guardada
let config = {
  subdomain: 'osw',
  whatsapp_token: null,
  system_prompt: `Eres el Asistente de Ventas IA de TerraBlinds. Responde SIEMPRE en español chileno.\n\n⚠️ REGLAS ABSOLUTAS:\n1. TODOS los precios son en PESOS CHILENOS (CLP). Usa el símbolo $. JAMÁS uses euros, dólares u otra moneda.\n2. Responde máximo 4-5 líneas.\n3. Si el cliente da medidas, calcula el precio de inmediato.\n4. SOLO ofrece productos del catálogo de TerraBlinds.\n\n== CATÁLOGO Y PRECIOS (por m²) ==\nRoller Blackout $38.000/m² | Roller Screen $38.000/m² | Roller Sunscreen $38.000/m²\nRoller Duo Traslúcido $45.000/m² | Roller Duo Blackout $45.000/m² | Roller Dual $56.000/m²\nPersianas, Toldos, Cierres de Terraza: precio por cotización según medidas\n\nCÁLCULO: Ancho(m) × Alto(m) × precio/m² | Mínimo 1m² | Instalación gratis en RM\nEjemplo: 1.5m × 2.0m Blackout = 3m² × $38.000 = $114.000\n\nWeb: terrablinds.cl | Cotizar: terrablinds.cl/quote | WhatsApp: +56935318909`,
  ai_provider: 'groq',
  ai_model: 'llama-3.3-70b-versatile',
};

try {
  const resp = await $http.request({
    method: 'GET',
    url: `${baseUrl}/internal/whatsapp/tenant-config?phone_number_id=${encodeURIComponent(phoneNumberId)}`,
    headers: { 'X-API-Secret': apiSecret },
  });
  const data = resp && (resp.body || resp.data || resp);
  if (data && data.subdomain) {
    config = {
      subdomain: data.subdomain,
      whatsapp_token: data.whatsapp_token,
      system_prompt: data.system_prompt || config.system_prompt,
      ai_provider: data.ai_provider || 'groq',
      ai_model: data.ai_model || 'llama-3.3-70b-versatile',
    };
  }
} catch(e) {
  // usa fallback
}

return [{ json: { ...($input.item.json), ...config, api_secret: apiSecret, base_url: baseUrl } }];

// Auto-registra el contacto en OmniFlow CRM cuando llega un mensaje WA
// No bloquea el flujo — errores se ignoran silenciosamente
const apiSecret = $json.api_secret;
const baseUrl = $json.base_url || 'https://osw.conectaai.cl/api/v1';
const subdomain = $json.subdomain;
const phone = $json.phone;
const contactName = $json.contact_name || 'Cliente WhatsApp';

try {
  await $http.request({
    method: 'POST',
    url: `${baseUrl}/internal/contact/upsert`,
    headers: { 'X-API-Secret': apiSecret, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      subdomain,
      external_id: phone,
      name: contactName,
      phone: '+' + phone,
      source: 'whatsapp',
    }),
  });
} catch(e) {
  // non-blocking — ignore
}

return [{ json: $input.item.json }];

// ─────────────────────────────────────────────────────────────────
// MEMORIA DE CONVERSACIÓN por número de teléfono
// Almacena los últimos 10 mensajes (5 intercambios) por usuario
// ─────────────────────────────────────────────────────────────────
const staticData = $getWorkflowStaticData('global');
const phone = $json.phone;
const systemPrompt = $json.system_prompt;
const userMessage = $json.message;

if (!staticData.conversations) staticData.conversations = {};
const history = staticData.conversations[phone] || [];

// Últimos 10 mensajes para contexto
const recentHistory = history.slice(-10);

// Array de mensajes para la IA
const messages = [
  { role: 'system', content: systemPrompt },
  ...recentHistory,
  { role: 'user', content: userMessage }
];

return [{ json: { ...($input.item.json), messages_for_ai: messages, history_count: recentHistory.length } }];

// Actualizar memoria de conversación con el nuevo intercambio
const staticData = $getWorkflowStaticData('global');
const phone = $json.phone;

if (!staticData.conversations) staticData.conversations = {};
const history = staticData.conversations[phone] || [];

history.push({ role: 'user',      content: $json.user_message });
history.push({ role: 'assistant', content: $json.ai_response });

// Máximo 20 mensajes en memoria (10 intercambios)
staticData.conversations[phone] = history.slice(-20);

return [{ json: $input.item.json }];

// ── Detectar y procesar comandos especiales de la IA ──────────────────────────
// COTIZACION_WA: → guarda cotización en CRM, elimina tag del mensaje
// ESCALAR_HUMANO → pausa el bot, notifica al agente, elimina tag del mensaje

const rawResponse = $json.ai_response || '';
const phone = $json.phone;
const subdomain = $json.subdomain;
const apiSecret = $json.api_secret;
const baseUrl = $json.base_url || 'https://osw.conectaai.cl/api/v1';

let cleanedResponse = rawResponse;
let shouldEscalate = false;

// ── Detectar ESCALAR_HUMANO ──────────────────────────────────────────────────
if (rawResponse.includes('ESCALAR_HUMANO')) {
  shouldEscalate = true;
  cleanedResponse = cleanedResponse.replace(/ESCALAR_HUMANO/g, '').trim();
  try {
    await $http.request({
      method: 'POST',
      url: `${baseUrl}/internal/whatsapp/handoff`,
      headers: { 'X-API-Secret': apiSecret, 'Content-Type': 'application/json' },
      body: JSON.stringify({ subdomain, phone: '+' + phone }),
    });
  } catch(e) { /* non-blocking */ }
}

// ── Detectar COTIZACION_WA: ──────────────────────────────────────────────────
const quoteMatch = rawResponse.match(/COTIZACION_WA:([\s\S]+?)(?=\n\nESCALAR_HUMANO|\n\n[A-Z]|$)/);
if (quoteMatch) {
  const quoteText = quoteMatch[1].trim();
  // Extraer valor total si está presente (ej: $114.000)
  const valueMatch = quoteText.match(/\$\s*([\d]{1,3}(?:[.,]\d{3})*)/);
  const quoteValue = valueMatch
    ? parseFloat(valueMatch[1].replace(/[.,]/g, ''))
    : null;
  try {
    await $http.request({
      method: 'POST',
      url: `${baseUrl}/internal/quote/save`,
      headers: { 'X-API-Secret': apiSecret, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        subdomain,
        external_id: phone,
        quote_text: quoteText,
        total_value: quoteValue,
      }),
    });
  } catch(e) { /* non-blocking */ }
  cleanedResponse = cleanedResponse.replace(/COTIZACION_WA:[\s\S]+?(?=\n\n[A-Z]|$)/, '').trim();
}

// Si el mensaje quedó vacío, usar respuesta de escalamiento o respuesta original
if (!cleanedResponse) {
  cleanedResponse = shouldEscalate
    ? '¡Perfecto! Te estoy conectando con un asesor que te ayudará de inmediato. 👨‍💼'
    : rawResponse;
}

return [{ json: { ...($input.item.json), ai_response: cleanedResponse, should_escalate: shouldEscalate } }];
